{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A simple project management API using Node.js",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "supertest": "^6.3.3"
  }
}

const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// In-memory repositories
const projectsRepo = {};
const tasksRepo = {};
const membersRepo = {};
const commentsRepo = {};

// Import routers
const projectRouter = require('./modules/projects/router');
const taskRouter = require('./modules/tasks/router');
const memberRouter = require('./modules/members/router');
const commentRouter = require('./modules/comments/router');

// Health endpoint
app.get('/health', (req, res) => {
  res.json({ ok: true });
});

// Use routers
app.use('/projects', projectRouter);
app.use('/projects/:projectId/tasks', taskRouter);
app.use('/projects/:projectId/members', memberRouter);
app.use('/projects/:projectId/tasks/:taskId/comments', commentRouter);

// Error handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ error: { code: 'INTERNAL_ERROR', message: 'Internal Server Error' } });
});

module.exports = app;

const crypto = require('crypto');

const commentsRepo = {};

function createComment(taskId, message) {
  const commentId = crypto.randomUUID();
  const comment = { id: commentId, taskId, message };
  if (!commentsRepo[taskId]) {
    commentsRepo[taskId] = [];
  }
  commentsRepo[taskId].push(comment);
  return comment;
}

function getComments(taskId) {
  return commentsRepo[taskId] || [];
}

module.exports = { createComment, getComments };

const crypto = require('crypto');

const membersRepo = {};

function addMember(projectId, userId, role) {
  if (!membersRepo[projectId]) {
    membersRepo[projectId] = [];
  }
  const existingMember = membersRepo[projectId].find(m => m.userId === userId);
  if (existingMember) {
    throw new Error('Member already exists');
  }
  const member = { id: crypto.randomUUID(), userId, role };
  membersRepo[projectId].push(member);
  return member;
}

function getMembers(projectId) {
  return membersRepo[projectId] || [];
}

module.exports = { addMember, getMembers };

const crypto = require('crypto');

const projectsRepo = {};

function createProject(name) {
  const projectId = crypto.randomUUID();
  const project = { id: projectId, name };
  projectsRepo[projectId] = project;
  return project;
}

function getProjects() {
  return Object.values(projectsRepo);
}

function getProjectById(projectId) {
  return projectsRepo[projectId];
}

module.exports = { createProject, getProjects, getProjectById };

const crypto = require('crypto');

const tasksRepo = {};

function createTask(projectId, title) {
  const taskId = crypto.randomUUID();
  const task = { id: taskId, projectId, title, status: 'pending' };
  if (!tasksRepo[projectId]) {
    tasksRepo[projectId] = [];
  }
  tasksRepo[projectId].push(task);
  return task;
}

function getTasks(projectId) {
  return tasksRepo[projectId] || [];
}

function updateTaskStatus(taskId, status) {
  for (const projectId in tasksRepo) {
    const task = tasksRepo[projectId].find(t => t.id === taskId);
    if (task) {
      task.status = status;
      return task;
    }
  }
  throw new Error('Task not found');
}

module.exports = { createTask, getTasks, updateTaskStatus };
